#!/usr/bin/env python3
"""Heuristic exploration planner: greedy utility + global BFS."""
import os, sys, json, argparse, math, random
from collections import deque
import numpy as np
from cogniplan_env import ExplorationEnv

def euclidean(a, b):
    return math.hypot(a[0]-b[0], a[1]-b[1])

class HeuristicPlanner:
    def __init__(self, epsilon=0.05, tabu_len=5):
        self.epsilon = epsilon
        self.tabu_len = tabu_len
        self.nodes_info = []
        self.coord_to_idx = {}
        self.adj = []

    def reset(self, nodes):
        self.coord_to_idx.clear()
        self.nodes_info = []
        for i, nd in enumerate(nodes):
            x, y = float(nd['coords'][0]), float(nd['coords'][1])
            self.coord_to_idx[(x, y)] = i
            self.nodes_info.append({'coords': (x, y), 'neighbors': []})
        n = len(nodes)
        self.adj = [[] for _ in range(n)]
        for i, nd in enumerate(nodes):
            for nb in nd.get('neighbors', []):
                key = (float(nb[0]), float(nb[1]))
                j = self.coord_to_idx.get(key)
                if j is not None and j != i:
                    self.adj[i].append(j)
        for i in range(n):
            for j in self.adj[i]:
                if i not in self.adj[j]:
                    self.adj[j].append(i)
        for i in range(n):
            self.nodes_info[i]['neighbors'] = self.adj[i]

    def bfs_path(self, start_idx, target_idx):
        n = len(self.adj)
        parent = [-1] * n
        q = deque([start_idx])
        visited = [False] * n
        visited[start_idx] = True
        while q:
            u = q.popleft()
            if u == target_idx:
                break
            for v in self.adj[u]:
                if not visited[v]:
                    visited[v] = True
                    parent[v] = u
                    q.append(v)
        return parent

    def reconstruct_path(self, start_idx, target_idx, parent):
        if target_idx < 0 or target_idx >= len(parent):
            return []
        if parent[target_idx] == -1 and start_idx != target_idx:
            return []
        path = []
        cur = target_idx
        for _ in range(len(parent)):
            if cur == start_idx:
                break
            path.append(cur)
            cur = parent[cur]
            if cur == -1:
                break
        return path[::-1]

    def get_closest_node_idx(self, pos):
        best_dist = float('inf')
        best_idx = -1
        for key, idx in self.coord_to_idx.items():
            d = euclidean(key, pos)
            if d < best_dist:
                best_dist = d
                best_idx = idx
        return best_idx

    def select_action(self, obs, curr_idx, visited_recent):
        neighbors_obs = obs.get('neighbors', [])
        neighbor_idxs = []
        for nb in neighbors_obs:
            key = (float(nb[0]), float(nb[1]))
            i = self.coord_to_idx.get(key)
            if i is not None:
                neighbor_idxs.append(i)
        if not neighbor_idxs:
            return None

        node_utils = [n['utility'] for n in obs['nodes']]
        if len(node_utils) != len(self.nodes_info):
            return random.choice(neighbors_obs)

        # 1) greedy neighbor with max utility > 0, not recently visited
        best_util = -1
        best_nb_idx = -1
        for ni in neighbor_idxs:
            if ni in visited_recent:
                continue
            if node_utils[ni] > best_util:
                best_util = node_utils[ni]
                best_nb_idx = ni
        if best_util > 0 and best_nb_idx >= 0:
            return self.nodes_info[best_nb_idx]['coords']

        # 2) epsilon-random
        if random.random() < self.epsilon:
            valid = [ni for ni in neighbor_idxs if ni not in visited_recent]
            if not valid:
                valid = neighbor_idxs
            ni = random.choice(valid)
            return self.nodes_info[ni]['coords']

        # 3) global BFS to max utility node
        global_best = -1
        global_best_util = -1
        for i, u in enumerate(node_utils):
            if u > global_best_util and i != curr_idx:
                global_best_util = u
                global_best = i
        if global_best >= 0:
            parent = self.bfs_path(curr_idx, global_best)
            if parent is not None and parent[global_best] != -1:
                path = self.reconstruct_path(curr_idx, global_best, parent)
                if path:
                    next_idx = path[0]
                    if next_idx in neighbor_idxs:
                        return self.nodes_info[next_idx]['coords']
        # fallback random unvisited
        valid = [ni for ni in neighbor_idxs if ni not in visited_recent]
        if not valid:
            valid = neighbor_idxs
        ni = random.choice(valid)
        return self.nodes_info[ni]['coords']


def run_episode(env, planner):
    obs = env.reset()
    planner.reset(obs['nodes'])
    total_dist = 0.0
    steps = 0
    max_steps = 128

    curr_idx = planner.get_closest_node_idx(tuple(obs['robot_pos']))
    visited_recent = []

    while steps < max_steps:
        if curr_idx not in visited_recent:
            visited_recent.append(curr_idx)
        if len(visited_recent) > planner.tabu_len + 1:
            visited_recent.pop(0)

        target_coord = planner.select_action(obs, curr_idx, set(visited_recent[-planner.tabu_len:]))
        if target_coord is None:
            break
        obs, info = env.step(target_coord)
        steps += 1
        if 'distance' in info:
            total_dist += info['distance']
        curr_idx = planner.get_closest_node_idx(tuple(obs['robot_pos']))
        if info.get('done', False):
            break

    metrics = env.get_metrics()
    return {
        'success': int(metrics.get('success', False)),
        'explored_rate': float(metrics.get('explored_rate', 0.0)),
        'travel_distance': float(metrics.get('travel_distance', total_dist)),
        'n_steps': int(metrics.get('n_steps', steps))
    }

def main():
    parser = argparse.ArgumentParser()
    parser.add_argument('--data_path', required=True)
    parser.add_argument('--checkpoint', required=True)
    parser.add_argument('--output', required=True)
    args = parser.parse_args()

    eval_config_path = os.path.join(args.data_path, 'eval_config.json')
    with open(eval_config_path) as f:
        eval_config = json.load(f)

    maps_root = os.path.join(args.data_path, 'maps_eval')
    env_types = eval_config.get('env_types', ['room', 'tunnel', 'outdoor'])

    planner = HeuristicPlanner(epsilon=0.05, tabu_len=5)

    per_episode = []
    per_type = {t: {'explored_rate': [], 'travel_distance': [], 'success_rate': []} for t in env_types}

    for env_type in env_types:
        type_dir = os.path.join(maps_root, env_type)
        if not os.path.isdir(type_dir):
            continue
        for fname in sorted(os.listdir(type_dir)):
            if not fname.endswith('.png'):
                continue
            map_path = os.path.join(type_dir, fname)
            env = ExplorationEnv(map_path=map_path)
            res = run_episode(env, planner)
            per_episode.append({
                'map_path': f'{env_type}/{fname}',
                'env_type': env_type,
                'success': res['success'],
                'travel_distance': res['travel_distance'],
                'explored_rate': res['explored_rate']
            })
            per_type[env_type]['explored_rate'].append(res['explored_rate'])
            per_type[env_type]['travel_distance'].append(res['travel_distance'])
            per_type[env_type]['success_rate'].append(res['success'])

    total_eps = len(per_episode)
    explored_rates = [ep['explored_rate'] for ep in per_episode]
    explored_rate_mean = np.mean(explored_rates) if total_eps else 0.0
    successes = [ep for ep in per_episode if ep['success']]
    success_rate = len(successes) / total_eps if total_eps else 0.0
    success_dists = [ep['travel_distance'] for ep in successes]
    travel_distance_mean = np.mean(success_dists) if successes else 0.0

    per_type_out = {}
    for t in env_types:
        if not per_type[t]['explored_rate']:
            per_type_out[t] = {'explored_rate': 0.0, 'travel_distance': 0.0, 'success_rate': 0.0}
            continue
        per_type_out[t] = {
            'explored_rate': float(np.mean(per_type[t]['explored_rate'])),
            'travel_distance': float(np.mean([d for d,s in zip(per_type[t]['travel_distance'], per_type[t]['success_rate']) if s==1]) if any(per_type[t]['success_rate']) else 0.0),
            'success_rate': float(np.mean(per_type[t]['success_rate']))
        }

    output = {
        'explored_rate': float(explored_rate_mean),
        'travel_distance': float(travel_distance_mean),
        'success_rate': float(success_rate),
        'per_episode': per_episode,
        'per_type': per_type_out,
        'total_episodes': total_eps
    }
    with open(args.output, 'w') as f:
        json.dump(output, f, indent=2)

if __name__ == '__main__':
    main()
